customCss:
.single-summary-card-container {
            font-family: 'Noto Sans KR', sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px 10px;
            background-color: #f4f6f7;
            margin: 25px 0;
            border-radius: 8px;
        }
        .single-summary-card {
            width: 100%;
            max-width: 700px;
            background-color: #ffffff;
            border-radius: 12px;
            box-shadow: 0 6px 18px rgba(0,0,0,0.1);
            padding: 25px;
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #e2e8f0;
            box-sizing: border-box;
        }
        .single-summary-card .card-header {
            display: flex;
            align-items: center;
            border-bottom: 2px solid #2c3e50;
            padding-bottom: 12px;
            margin-bottom: 15px;
        }
        .single-summary-card .card-header-icon {
            font-size: 30px;
            color: #2c3e50;
            margin-right: 12px;
        }
        .single-summary-card .card-header h3 {
            font-size: 20px;
            color: #2c3e50;
            margin: 0;
            line-height: 1.3;
            font-weight: 700;
        }
        .single-summary-card .card-content {
            font-size: 15.5px;
            line-height: 1.7;
            color: #333;
        }
        .single-summary-card .card-content .section {
            margin-bottom: 12px;
        }
        .single-summary-card .card-content strong {
            color: #2c3e50;
            font-weight: 600;
        }
        .single-summary-card .card-content .highlight {
            background-color: #e8f4fd;
            padding: 2px 6px;
            border-radius: 3px;
            font-weight: bold;
            color: #2c3e50;
        }
        .single-summary-card .card-content .formula {
            background-color: #f8f9fa;
            padding: 8px 12px;
            border-radius: 4px;
            font-size: 0.95em;
            text-align: center;
            margin-top: 5px;
            border: 1px solid #e2e8f0;
            font-family: monospace;
            color: #2c3e50;
        }
        .single-summary-card .card-footer {
            font-size: 13.5px;
            color: #7f8c8d;
            text-align: center;
            padding-top: 12px;
            border-top: 1px dashed #e2e8f0;
            margin-top: 15px;
        }
        @media (max-width: 768px) {
            .single-summary-card { padding: 18px; }
            .single-summary-card .card-header-icon { font-size: 24px; }
            .single-summary-card .card-header h3 { font-size: 18px; }
            .single-summary-card .card-content { font-size: 14.5px; }
        }
